{
	"params": {
		"1": {
			"label": "English text",
			"example": "English",
			"type": "string",
			"suggested": true
		},
		"2": {
			"label": "Kana/kanji text",
			"example": "英語",
			"type": "string",
			"required": true
		},
		"3": {
			"label": "Romanized (rōmaji) text",
			"example": "eigo",
			"type": "string",
			"suggested": true
		},
		"lead": {
			"label": "Label writing systems",
			"description": "If 'yes', shows \"Japanese: \", etc., as leads",
			"example": "yes",
			"type": "string",
			"suggested": true
		},
		"extra": {
			"aliases": [
				"4"
			],
			"label": "First extra text",
			"type": "string"
		},
		"extra2": {
			"aliases": [
				"5"
			],
			"label": "Second extra text",
			"type": "string"
		},
		"group": {
			"label": "Footnote reference group",
			"example": "lower-alpha",
			"type": "string",
			"suggested": true
		}
	},
	"description": "Like {{Nihongo}}, allows kanji/kana and rōmaji text, but puts them in footnotes"
}
</templatedata>

